import{_ as t,c as r,o as i,ag as o}from"./chunks/framework.Dj4VfQLU.js";const p=JSON.parse('{"title":"Versioning policy","description":"","frontmatter":{"icon":"code-merge"},"headers":[],"relativePath":"versioning-policy.md","filePath":"versioning-policy.md"}'),a={name:"versioning-policy.md"};function n(s,e,l,d,c,g){return i(),r("div",null,e[0]||(e[0]=[o('<h1 id="versioning-policy" tabindex="-1">Versioning policy <a class="header-anchor" href="#versioning-policy" aria-label="Permalink to &quot;Versioning policy&quot;">​</a></h1><p>BetterTaxi follows a structured and predictable versioning strategy designed to provide stability, clarity, and flexibility for all levels of users — from independent developers to enterprise-grade deployments.</p><hr><h4 id="📌-semantic-versioning-semver" tabindex="-1">📌 Semantic Versioning (SemVer) <a class="header-anchor" href="#📌-semantic-versioning-semver" aria-label="Permalink to &quot;📌 Semantic Versioning (SemVer)&quot;">​</a></h4><p>We use <strong>Semantic Versioning (SemVer)</strong> format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MAJOR.MINOR.PATCH  →  e.g., 2.3.1</span></span></code></pre></div><ul><li><strong>MAJOR</strong>: Incompatible API or architecture changes (rare, typically once a year)</li><li><strong>MINOR</strong>: New features or service extensions that remain backward compatible</li><li><strong>PATCH</strong>: Bug fixes, UI adjustments, or minor enhancements</li></ul><hr><h4 id="🔀-server-client-version-coordination" tabindex="-1">🔀 Server &amp; Client Version Coordination <a class="header-anchor" href="#🔀-server-client-version-coordination" aria-label="Permalink to &quot;🔀 Server &amp; Client Version Coordination&quot;">​</a></h4><ul><li><strong>Server-side</strong> and <strong>Client-side (Flutter apps)</strong> are versioned <strong>independently</strong> for MINOR and PATCH updates</li><li>However, <strong>MAJOR versions are aligned</strong> across server and client to ensure compatibility and coherence</li><li>Example: <ul><li><code>Server 3.1.0</code> may still work with <code>Driver App 3.0.2</code></li><li>But <code>Server 4.x.x</code> would expect compatible <code>Client 4.x.x</code> apps</li></ul></li></ul><hr><h4 id="📅-release-cycle" tabindex="-1">📅 Release Cycle <a class="header-anchor" href="#📅-release-cycle" aria-label="Permalink to &quot;📅 Release Cycle&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Type</th><th>Frequency</th><th>Description</th></tr></thead><tbody><tr><td><strong>Major</strong></td><td>~ Every 12 months</td><td>UI/UX redesigns, architecture updates</td></tr><tr><td><strong>Feature</strong></td><td>~ Every 3 months</td><td>New modules, service types, partner tools</td></tr><tr><td><strong>Patch</strong></td><td>As needed</td><td>Bug fixes, compatibility patches</td></tr><tr><td><strong>Security Fixes</strong></td><td>Immediate when needed</td><td>Delivered outside normal cycle if urgent</td></tr></tbody></table><hr><h4 id="🔙-backward-compatibility" tabindex="-1">🔙 Backward Compatibility <a class="header-anchor" href="#🔙-backward-compatibility" aria-label="Permalink to &quot;🔙 Backward Compatibility&quot;">​</a></h4><ul><li><strong>Backward compatibility</strong> is <strong>guaranteed</strong> for all MINOR and PATCH updates</li><li><strong>Rollback compatibility</strong> is <strong>not guaranteed</strong>, so always <strong>backup your server before upgrading</strong></li><li><strong>Breaking changes</strong>, if any, are limited to <strong>MAJOR releases only</strong></li></ul><hr><h4 id="📣-update-notifications" tabindex="-1">📣 Update Notifications <a class="header-anchor" href="#📣-update-notifications" aria-label="Permalink to &quot;📣 Update Notifications&quot;">​</a></h4><p><strong>How You’ll Know About Updates:</strong></p><ul><li><strong>Codecanyon</strong>: <ul><li>You’ll receive emails when new versions are published</li><li>Changelogs are listed on the Codecanyon item page</li></ul></li><li><strong>Documentation Changelog Section</strong>: <ul><li>You can refer to this documentation’s Changelog page for a full update history</li></ul></li><li><strong>Website</strong>:<br> Always check <a href="https://bettersuite.io/" target="_blank" rel="noreferrer">bettersuite.io</a> for the latest product release announcements</li></ul><hr><h4 id="🔧-customizations-updates" tabindex="-1">🔧 Customizations &amp; Updates <a class="header-anchor" href="#🔧-customizations-updates" aria-label="Permalink to &quot;🔧 Customizations &amp; Updates&quot;">​</a></h4><p><strong>For Self-Managed Users:</strong></p><ul><li>Use <strong>Version Control Systems (VCS)</strong> (e.g., Git) to manage your local customizations</li><li>When updates are released, we recommend using: <ul><li><code>git rebase</code> or</li><li><code>git cherry-pick</code><br> to integrate upstream changes into your customized codebase</li></ul></li></ul><p><strong>For Pro Plus Plan Customers:</strong></p><ul><li>Our team <strong>handles upgrades and conflict resolution</strong> internally</li><li>Custom features are preserved where possible and adapted during version transitions.</li></ul>',26)]))}const h=t(a,[["render",n]]);export{p as __pageData,h as default};
